function PrivacyPolicy({ content, lastUpdated, sections }) {
  const { div, article, aside, h1, h2, p, a, nav, time } = tags;
  const [activeSection, setActiveSection] = createSignal('');

  onMount(() => {
    const observer = new IntersectionObserver((entries) => {
      entries.forEach(e => { if (e.isIntersecting) setActiveSection(e.target.id); });
    }, { threshold: 0.5 });
    sections.forEach(s => {
      const el = document.getElementById(s.id);
      if (el) observer.observe(el);
    });
    return () => observer.disconnect();
  });

  return div({ class: css('_grid _gc1 _lg:gc[1fr_280px] _gap8 _py12 _px6 _maxw[1200px] _mx[auto]') },
    article({ class: css('_prose _maxw[none]') },
      div({ class: css('_mb8') },
        h1({ class: css('_heading2 _mb2') }, 'Privacy Policy'),
        time({ class: css('_textsm _fgmuted') }, `Last updated: ${lastUpdated}`)
      ),
      ...sections.map(s =>
        div({ id: s.id, class: css('_mb8 _scroll[mt-20]') },
          h2({ class: css('_heading4 _mb4') }, s.title),
          div({ class: css('_prose') }, s.content)
        )
      ),
      div({ class: css('carbon-divider _my8') }),
      p({ class: css('_fgmuted _textsm') }, 'Questions? Contact us at privacy@example.com')
    ),
    aside({ class: css('_hidden _lg:block') },
      nav({ class: css('_sticky _top20 _flex _col _gap2') },
        p({ class: css('_textsm _font500 _fgmuted _mb2') }, 'On this page'),
        ...sections.map(s =>
          a({
            href: `#${s.id}`,
            class: css(`_textsm _py1 _pl3 _borderL[2px] _trans ${activeSection() === s.id ? '_borderPrimary _fgPrimary' : '_borderTransparent _fgmuted'}`),
            onclick: (e) => { e.preventDefault(); document.getElementById(s.id)?.scrollIntoView({ behavior: 'smooth' }); }
          }, s.title)
        ),
        div({ class: css('_mt4 _pt4 _borderT') },
          Button({ variant: 'ghost', size: 'sm', onclick: () => window.print() },
            icon('printer', { size: '14' }), 'Print'
          )
        )
      )
    )
  );
}

