function CookiePolicy({ categories, lastUpdated }) {
  const { div, h1, h2, h3, p, time, button } = tags;
  const [expanded, setExpanded] = createSignal({});

  const toggle = (id) => setExpanded({ ...expanded(), [id]: !expanded()[id] });

  return div({ class: css('_flex _col _gap8 _py12 _px6 _maxw[800px] _mx[auto]') },
    div({ class: css('_mb4') },
      h1({ class: css('_heading2 _mb2') }, 'Cookie Policy'),
      time({ class: css('_textsm _fgmuted') }, `Last updated: ${lastUpdated}`)
    ),
    div({ class: css('_prose _mb8') },
      p({}, 'This policy explains how we use cookies and similar technologies on our website.')
    ),
    div({ class: css('_flex _col _gap4') },
      ...categories.map(cat =>
        div({ class: css('carbon-card _r2 _overflow[hidden]') },
          button({
            class: css('_wfull _flex _jcsb _aic _p4 _bg0 _border0 _cursor[pointer]'),
            onclick: () => toggle(cat.id)
          },
            div({ class: css('_flex _aic _gap3') },
              div({ class: css('_w10 _h10 _rfull _bgPrimary/10 _flex _center') },
                icon(cat.icon || 'cookie', { class: css('_fgPrimary') })
              ),
              div({ class: css('_tl') },
                h3({ class: css('_heading5') }, cat.name),
                p({ class: css('_textsm _fgmuted') }, cat.description)
              )
            ),
            icon(expanded()[cat.id] ? 'chevron-up' : 'chevron-down', { class: css('_fgmuted') })
          ),
          expanded()[cat.id] ? div({ class: css('_px4 _pb4 _prose') },
            div({ class: css('carbon-divider _mb4') }),
            p({}, cat.details),
            cat.cookies?.length > 0 ? div({ class: css('_mt4') },
              h3({ class: css('_textsm _font500 _mb2') }, 'Cookies used:'),
              ...cat.cookies.map(c =>
                div({ class: css('_flex _jcsb _py2 _borderB _borderB[last]:0') },
                  span({ class: css('_textsm _font500') }, c.name),
                  span({ class: css('_textsm _fgmuted') }, c.duration)
                )
              )
            ) : null
          ) : null
        )
      )
    ),
    div({ class: css('_mt4') },
      Button({ variant: 'primary' }, icon('settings'), 'Manage Cookie Preferences')
    )
  );
}

